import React, { useState } from "react";

const API_BASE = process.env.REACT_APP_API_BASE_URL || "";

const FindTicket = () => {
  const [from, setFrom] = useState("");
  const [to, setTo] = useState("");
  const [date, setDate] = useState("");
  const [tickets, setTickets] = useState([]);
  const [loading, setLoading] = useState(false);

  const handleSearch = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      const res = await fetch(
        `${API_BASE}/api/tickets?from=${from}&to=${to}&date=${date}`,
        {
          headers: {
            Authorization: `Bearer ${localStorage.getItem("token") || ""}`,
          },
        }
      );
      const data = await res.json();
      if (res.ok) {
        setTickets(data);
      } else {
        alert(data.error || "Error fetching tickets");
        setTickets([]);
      }
    } catch (err) {
      alert("Network error: " + err.message);
      setTickets([]);
    }

    setLoading(false);
  };

  const handleUnlock = async (ticketId) => {
    try {
      const res = await fetch(`${API_BASE}/api/unlock/${ticketId}`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${localStorage.getItem("token") || ""}`,
        },
      });
      const data = await res.json();
      if (res.ok) {
        alert("Unlocked! Contact number visible now.");
        // refresh tickets
        setTickets((prev) =>
          prev.map((t) =>
            t.id === ticketId ? { ...t, unlocked: true } : t
          )
        );
      } else {
        alert(data.error || "Payment failed");
      }
    } catch (err) {
      alert("Network error: " + err.message);
    }
  };

  return (
    <div className="flex justify-center items-center min-h-screen bg-gray-100 p-4">
      <div className="bg-white shadow-lg rounded-2xl p-6 w-full max-w-2xl">
        <h2 className="text-2xl font-bold text-center mb-6">Find Ticket</h2>

        <form onSubmit={handleSearch} className="space-y-4">
          <div>
            <label className="block mb-1 font-medium">From Station</label>
            <input
              type="text"
              value={from}
              onChange={(e) => setFrom(e.target.value)}
              placeholder="Enter starting station"
              className="w-full border rounded-xl px-3 py-2"
              required
            />
          </div>
          <div>
            <label className="block mb-1 font-medium">To Station</label>
            <input
              type="text"
              value={to}
              onChange={(e) => setTo(e.target.value)}
              placeholder="Enter destination station"
              className="w-full border rounded-xl px-3 py-2"
              required
            />
          </div>
          <div>
            <label className="block mb-1 font-medium">Date</label>
            <input
              type="date"
              value={date}
              onChange={(e) => setDate(e.target.value)}
              className="w-full border rounded-xl px-3 py-2"
              required
            />
          </div>
          <button
            type="submit"
            className="w-full bg-blue-600 text-white py-2 rounded-xl hover:bg-blue-700 transition"
            disabled={loading}
          >
            {loading ? "Searching..." : "Search"}
          </button>
        </form>

        {/* Ticket results */}
        <div className="mt-6 space-y-4">
          {tickets.length === 0 && !loading && (
            <p className="text-center text-red-600 font-medium">No tickets found</p>
          )}

          {tickets.map((ticket) => (
            <div
              key={ticket.id}
              className="border rounded-xl p-4 shadow-sm bg-gray-50"
            >
              <p>
                <strong>Train:</strong> {ticket.train_number} - {ticket.train_name}
              </p>
              <p>
                <strong>Holder:</strong> {ticket.holder_name}
              </p>
              <p>
                <strong>From:</strong> {ticket.from_station} → <strong>To:</strong>{" "}
                {ticket.to_station}
              </p>
              <p>
                <strong>Date:</strong> {ticket.travel_date}
              </p>
              <p>
                <strong>Seats:</strong> {ticket.seats}
              </p>

              {ticket.unlocked ? (
                <p className="text-green-600 font-semibold">
                  Contact: {ticket.contact_phone}
                </p>
              ) : (
                <button
                  onClick={() => handleUnlock(ticket.id)}
                  className="mt-2 bg-green-600 text-white px-4 py-1 rounded hover:bg-green-700"
                >
                  Unlock Contact (₹20)
                </button>
              )}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default FindTicket;
